return [{
  json: {
    response: "Lead guardado exitosamente en Supabase y GHL. Se envió correo de bienvenida a " + $node["Parse Input"].json.email + "."
  }
}];

const query = $input.first().json.query;
if (!query || !query.some_input) {
  return $input.all();
}

try {
  let parsed = {};
  const rawInput = query.some_input;

  if (typeof rawInput === 'object') {
    parsed = rawInput;
  } else if (typeof rawInput === 'string') {
    try {
      parsed = JSON.parse(rawInput);
    } catch (jsonErr) {
      parsed = {};
      const extractField = (labels, text) => {
        for (const label of labels) {
          const pattern = new RegExp(label + '\\s*:\\s*(.*?)(?:\\s*[,\\n]\\s*(?:Nombre|Name|Correo|Email|Teléfono|Telefono|Phone|Materia|Subject|Nivel|Grade|Descripción|Descripcion|Description)|$)', 'i');
          const match = text.match(pattern);
          if (match && match[1]) {
            return match[1].trim();
          }
        }
        return '';
      };

      parsed.nombre = extractField(['Nombre', 'Name'], rawInput);
      parsed.email = extractField(['Correo', 'Email'], rawInput);
      parsed.telefono = extractField(['Teléfono', 'Telefono', 'Phone', 'Tel', 'Celular'], rawInput);
      parsed.materia = extractField(['Materia', 'Subject', 'Curso'], rawInput);
      parsed.nivel = extractField(['Nivel', 'Grade', 'Curso_nivel'], rawInput);
      parsed.descripcion = extractField(['Descripción', 'Descripcion', 'Description', 'Notes'], rawInput);
    }
  }

  const nombre = parsed.nombre || parsed.name || 'Sin nombre';
  const email = parsed.email || parsed.correo || parsed.email_address || '';
  const telefono = parsed.telefono || parsed.phone || parsed.tel || parsed.celular || '';
  const materia = parsed.materia || parsed.subject || parsed.curso || '';
  const nivel = parsed.nivel || parsed.grade || parsed.curso_nivel || '';
  const descripcion = parsed.descripcion || parsed.description || parsed.notes || 'Sin descripción';
  const reference_email = parsed.reference_email || '';

  // Detect support_type
  let support_type = parsed.support_type || parsed.tipo_apoyo;
  if (!support_type) {
    const textToAnalyze = (descripcion + ' ' + materia).toLowerCase();
    if (textToAnalyze.includes('examen') || textToAnalyze.includes('parcial') || textToAnalyze.includes('prueba') || textToAnalyze.includes('test') || textToAnalyze.includes('quiz') || textToAnalyze.includes('final')) {
      support_type = 'examen';
    } else if (textToAnalyze.includes('tarea') || textToAnalyze.includes('deber') || textToAnalyze.includes('ejercicio') || textToAnalyze.includes('proyecto') || textToAnalyze.includes('trabajo') || textToAnalyze.includes('hoja de trabajo')) {
      support_type = 'tareas';
    } else if (textToAnalyze.includes('recupera') || textToAnalyze.includes('remedial') || textToAnalyze.includes('aplazo')) {
      support_type = 'recuperacion';
    } else if (textToAnalyze.includes('demo') || textToAnalyze.includes('demostracion') || textToAnalyze.includes('gratis')) {
      support_type = 'demo';
    } else if (textToAnalyze.includes('refuerzo') || textToAnalyze.includes('nivelacion') || textToAnalyze.includes('apoyo') || textToAnalyze.includes('clases') || textToAnalyze.includes('explicar') || textToAnalyze.includes('aprender')) {
      support_type = 'refuerzo';
    } else {
      support_type = 'otro';
    }
  }

  return [{
    json: {
      nombre,
      email,
      telefono,
      materia,
      nivel,
      descripcion,
      support_type,
      reference_email
    }
  }];
} catch (e) {
  return [{
    json: {
      nombre: 'Sin nombre',
      email: '',
      telefono: '',
      materia: '',
      nivel: '',
      descripcion: 'Sin descripción',
      support_type: 'otro',
      reference_email: ''
    }
  }];
}
